import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Dashboard.css';

const API_BASE = 'https://nordcomply-api.dshvan5.workers.dev';

export default function Dashboard() {
  const navigate = useNavigate();
  const [tenants, setTenants] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [deleteConfirm, setDeleteConfirm] = useState(null);

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    try {
      setLoading(true);
      const tenantsRes = await fetch(`${API_BASE}/api/tenants`);
      if (!tenantsRes.ok) throw new Error('Failed to fetch tenants');
      const tenantsData = await tenantsRes.json();
      setTenants(tenantsData);
    } catch (err) {
      console.error('Error:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function handleDeleteTenant(tenantId, tenantName) {
    try {
      const response = await fetch(
        `${API_BASE}/api/tenant?tenantId=${tenantId}`,
        { method: 'DELETE' }
      );

      if (!response.ok) throw new Error('Failed to delete tenant');

      setDeleteConfirm(null);
      await fetchData();
    } catch (err) {
      console.error('Error deleting tenant:', err);
      alert(`Fejl ved sletning: ${err.message}`);
    }
  }

  return (
    <div className="dashboard">
      <div className="dashboard__header">
        <h1>Velkommen, Dany!</h1>
        <p>Få overblik over dine M365 tenants og sikkerhedsstatus</p>
      </div>

      <div className="dashboard__stats">
        <div className="stat-card">
          <div className="stat-label">ANTAL TENANTS</div>
          <div className="stat-value">{tenants.length}</div>
          <div className="stat-desc">Importerede tenants</div>
        </div>

        <div className="stat-card">
          <div className="stat-label">STATUS</div>
          <div className="stat-value">
            {tenants.length > 0 ? '✓ Aktiv' : 'Ingen data'}
          </div>
          <div className="stat-desc">System status</div>
        </div>

        <div className="stat-card">
          <div className="stat-label">LAST SYNCED</div>
          <div className="stat-value">--</div>
          <div className="stat-desc">Sidst opdateret</div>
        </div>
      </div>

      <div className="dashboard__tenants">
        <h2>Dine Tenants</h2>

        {loading ? (
          <p className="loading">Indlæser...</p>
        ) : tenants.length === 0 ? (
          <div className="empty-state">
            <p>Du har ikke importeret nogen tenants endnu.</p>
            <button
              onClick={() => navigate('/admin')}
              className="btn-primary"
            >
              Importér din første tenant
            </button>
          </div>
        ) : (
          <div className="tenants-grid">
            {tenants.map((tenant) => (
              <div key={tenant.id} className="tenant-card">
                <div className="tenant-card__header">
                  <h3>{tenant.name}</h3>
                  <span className="tenant-badge">✓ Aktiv</span>
                </div>
                <div className="tenant-card__info">
                  <p><strong>Tenant ID:</strong></p>
                  <code>{tenant.tenantId}</code>
                  <p><strong>Tilføjet:</strong> {new Date(tenant.addedAt).toLocaleDateString('da-DK')}</p>
                </div>
                <div className="tenant-card__actions">
                  {deleteConfirm === tenant.id ? (
                    <div className="delete-confirm">
                      <p>Slet "{tenant.name}"?</p>
                      <button
                        onClick={() => handleDeleteTenant(tenant.tenantId, tenant.name)}
                        className="btn-delete-confirm"
                      >
                        Ja, slet
                      </button>
                      <button
                        onClick={() => setDeleteConfirm(null)}
                        className="btn-cancel"
                      >
                        Annuller
                      </button>
                    </div>
                  ) : (
                    <button
                      onClick={() => setDeleteConfirm(tenant.id)}
                      className="btn-delete"
                    >
                      🗑️ Slet
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
